import { GoldRushClient } from "@covalenthq/client-sdk";

const client = new GoldRushClient(process.env.GOLDRUSH_API_KEY);

async function scoreMemeRisk(chainName, tokenAddress) {
  const [events, approvals] = await Promise.all([
    client.BaseService.getLogEventsByAddress(chainName, tokenAddress),
    client.SecurityService.getApprovals(chainName, tokenAddress),
  ]);
  const transfers = (events.data?.items ?? []).filter(e => e.decoded?.name === "Transfer");
  const uniqueHolders = new Set(transfers.map(e => e.decoded?.params?.find(p => p.name === "to")?.value)).size;
  const riskScore = uniqueHolders < 50 ? 90 : uniqueHolders < 200 ? 60 : 20;
  return { tokenAddress, riskScore, uniqueHolders };
}
